patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..1b1ff8670bc0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7885,6 +7885,7 @@ static Instruction *foldFCmpFNegCommonOp(FCmpInst &I) {
   return new FCmpInst(Pred, Op0, Zero, "", &I);
 }

+
 Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   bool Changed = false;

@@ -8068,6 +8069,39 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   }
   }

+  // Handle fcmp with fabs pattern from select:
+  // fcmp [ou]eq (fabs x), 0 --> fcmp [ou]eq x, 0
+  // fcmp [ou]ne (fabs x), 0 --> fcmp [ou]ne x, 0
+  if (match(Op1, m_AnyZeroFP())) {
+    if (auto *SI = dyn_cast<SelectInst>(Op0)) {
+      if (SI->hasOneUse()) {
+        Value *TrueVal = SI->getTrueValue();
+        Value *FalseVal = SI->getFalseValue();
+        Value *SrcX = nullptr;
+
+        // fabs pattern: select cond, X, -X or select cond, -X, X
+        Value *TmpX;
+        if (match(FalseVal, m_FNeg(m_Value(TmpX))) && TmpX == TrueVal) {
+          SrcX = TmpX;
+        } else if (match(TrueVal, m_FNeg(m_Value(TmpX))) && TmpX == FalseVal) {
+          SrcX = TmpX;
+        }
+
+        if (SrcX) {
+          switch (Pred) {
+          case FCmpInst::FCMP_OEQ:
+          case FCmpInst::FCMP_ONE:
+          case FCmpInst::FCMP_UEQ:
+          case FCmpInst::FCMP_UNE:
+            return new FCmpInst(Pred, SrcX, Op1, "", &I);
+          default:
+            break;
+          }
+        }
+      }
+    }
+  }
+
   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
     return R;

@@ -8180,3 +8214,4 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {

   return Changed ? &I : nullptr;
 }
+

